from __future__ import absolute_import

from email.parser import FeedParser
import logging
import os

from pip.basecommand import Command
from pip.status_codes import SUCCESS, ERROR
from pip._vendor import pkg_resources
from pip._vendor.packaging.utils import canonicalize_name


logger = logging.getLogger(__name__)


class ShowCommand(Command):
    """Show information about one or more installed packages."""
    name = 'show'
    usage = """
      %prog [options] <package> ..."""
    summary = 'Show information about installed packages.'

    def __init__(self, *args, **kw):
        super(ShowCommand, self).__init__(*args, **kw)
        self.cmd_opts.add_option(
            '-f', '--files',
            dest='files',
            action='store_true',
            default=False,
            help='Show the full list of installed files for each package.')

        self.parser.insert_option_group(0, self.cmd_opts)

    def run(self, options, args):
        if not args:
            logger.warning('ERROR: Please provide a package name or names.')
            return ERROR
        query = args

        results = search_packages_info(query)
        if not print_results(
                results, list_files=options.files, verbose=options.verbose):
            return ERROR
        return SUCCESS

def _get_files_and_metadata(dist):
    """Extrai a lista de arquivos e a string de metadados baseada no tipo de distribuição."""
    file_list = None
    metadata = None

    if isinstance(dist, pkg_resources.DistInfoDistribution):
        # Lógica para o formato mais moderno (.dist-info)
        if dist.has_metadata('RECORD'):
            lines = dist.get_metadata_lines('RECORD')
            paths = [os.path.join(dist.location, l.split(',')[0]) for l in lines]
            file_list = [os.path.relpath(p, dist.location) for p in paths]
            
        if dist.has_metadata('METADATA'):
            metadata = dist.get_metadata('METADATA')
    else:
        # Lógica de fallback para o formato antigo (.egg-info)
        if dist.has_metadata('installed-files.txt'):
            lines = dist.get_metadata_lines('installed-files.txt')
            paths = [os.path.join(dist.egg_info, p) for p in lines]
            file_list = [os.path.relpath(p, dist.location) for p in paths]
            
        if dist.has_metadata('PKG-INFO'):
            metadata = dist.get_metadata('PKG-INFO')

    return file_list, metadata


def _get_installer(dist):
    """Extrai o nome do instalador, retornando o primeiro valor válido encontrado."""
    if dist.has_metadata('INSTALLER'):
        for line in dist.get_metadata_lines('INSTALLER'):
            if line.strip():
                return line.strip()
    return None


def _parse_feed_metadata(metadata):
    """Faz o parse da string crua de metadados em um dicionário estruturado."""
    if not metadata:
        return {}

    feed_parser = FeedParser()
    feed_parser.feed(metadata)
    pkg_info_dict = feed_parser.close()

    # Extrai as chaves simples usando um Dict Comprehension
    keys_to_extract = ('metadata-version', 'summary', 'home-page', 
                       'author', 'author-email', 'license')
    parsed_info = {key: pkg_info_dict.get(key) for key in keys_to_extract}

    # Extrai os headers repetidos (Classifiers) usando List Comprehension
    parsed_info['classifiers'] = [
        line[len('Classifier: '):]
        for line in metadata.splitlines()
        if line.startswith('Classifier: ')
    ]
    
    return parsed_info

def search_packages_info(query):
    """
    Gather details from installed distributions. Print distribution name,
    version, location, and installed files. Installed files requires a
    pip generated 'installed-files.txt' in the distributions '.egg-info'
    directory.
    """
    # 1. Aplicando o Dictionary Comprehension (Dica do SonarQube absorvida!)
    installed = {
        canonicalize_name(p.project_name): p 
        for p in pkg_resources.working_set
    }
    
    query_names = [canonicalize_name(name) for name in query]

    for pkg in query_names:
        if pkg not in installed:
            continue
            
        dist = installed[pkg]
        package = {
            'name': dist.project_name,
            'version': dist.version,
            'location': dist.location,
            'requires': [dep.project_name for dep in dist.requires()],
        }

        # 2. Delegando as lógicas pesadas para os especialistas
        file_list, metadata = _get_files_and_metadata(dist)

        if dist.has_metadata('entry_points.txt'):
            package['entry_points'] = dist.get_metadata_lines('entry_points.txt')

        installer = _get_installer(dist)
        if installer:
            package['installer'] = installer

        # 3. Atualiza o pacote com o parse estruturado
        parsed_metadata = _parse_feed_metadata(metadata)
        package.update(parsed_metadata)

        if file_list:
            package['files'] = sorted(file_list)
            
        yield package

def _print_verbose_details(dist):
    """Imprime os detalhes extras de metadados se o modo verbose estiver ativado."""
    logger.info("Metadata-Version: %s", dist.get('metadata-version', ''))
    logger.info("Installer: %s", dist.get('installer', ''))
    
    logger.info("Classifiers:")
    for classifier in dist.get('classifiers', []):
        logger.info("  %s", classifier)
        
    logger.info("Entry-points:")
    for entry in dist.get('entry_points', []):
        logger.info("  %s", entry.strip())
def _print_file_list(dist):
    """Imprime a lista de arquivos ou alerta sobre a falta do txt."""
    if "files" not in dist:
        logger.info("Cannot locate installed-files.txt")
        return
        
    logger.info("Files:")
    for line in dist.get('files', []):
        logger.info("  %s", line.strip())

def print_results(distributions, list_files=False, verbose=False):
    """
    Print the informations from installed distributions found.
    """
    results_printed = False
    for i, dist in enumerate(distributions):
        results_printed = True
        
        if i > 0:
            logger.info("---")
        # Bloco de informações padrão
        logger.info("Name: %s", dist.get('name', ''))
        logger.info("Version: %s", dist.get('version', ''))
        logger.info("Summary: %s", dist.get('summary', ''))
        logger.info("Home-page: %s", dist.get('home-page', ''))
        logger.info("Author: %s", dist.get('author', ''))
        logger.info("Author-email: %s", dist.get('author-email', ''))
        logger.info("License: %s", dist.get('license', ''))
        logger.info("Location: %s", dist.get('location', ''))
        logger.info("Requires: %s", ', '.join(dist.get('requires', [])))
        # Delegação das tarefas pesadas
        if verbose:
            _print_verbose_details(dist)
        if list_files:
            _print_file_list(dist)
    return results_printed
